import { useMemo, useState } from "react";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";

const FAQS = [
  { q: "How is a Canadian mortgage different from a US mortgage?", a: "Canadian mortgages commonly use semi-annual compounding, shorter mortgage terms, and amortization periods that may be longer than the selected term." },
  { q: "What is CMHC insurance?", a: "CMHC mortgage insurance protects the lender when a borrower has a smaller down payment, generally under 20%." },
  { q: "What is semi-annual compounding in Canadian mortgages?", a: "Canadian mortgage rates are typically quoted with semi-annual compounding, then converted into an effective monthly payment rate." },
  { q: "What is the maximum amortization period in Canada?", a: "Maximum amortization depends on mortgage type and rules in effect. Many insured mortgages use a 25-year maximum, while some uninsured mortgages may allow longer terms." },
  { q: "What is the First Home Buyer Incentive in Canada?", a: "The First-Time Home Buyer Incentive was a shared-equity program. Program availability and rules can change, so buyers should check current Government of Canada guidance." },
];

const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";
const cad = (v: number, d = 0) => new Intl.NumberFormat("en-CA", { style: "currency", currency: "CAD", maximumFractionDigits: d }).format(Number.isFinite(v) ? v : 0);
function cmhcRate(downPct: number) { if (downPct >= 20) return 0; if (downPct >= 15) return 0.028; if (downPct >= 10) return 0.031; return 0.04; }
function canadianPayment(principal: number, nominalRate: number, years: number) {
  const monthlyRate = Math.pow(1 + nominalRate / 100 / 2, 2 / 12) - 1;
  const n = years * 12;
  if (principal <= 0 || n <= 0) return 0;
  return monthlyRate === 0 ? principal / n : principal * monthlyRate / (1 - Math.pow(1 + monthlyRate, -n));
}

export default function CanadianMortgageCalculator() {
  const [home, setHome] = useState(400000);
  const [down, setDown] = useState(40000);
  const [amortization, setAmortization] = useState(25);
  const [term, setTerm] = useState(5);
  const [rate, setRate] = useState(5);
  const result = useMemo(() => {
    const downPct = home > 0 ? down / home * 100 : 0;
    const base = Math.max(0, home - down);
    const premium = base * cmhcRate(downPct);
    const loan = base + premium;
    const monthly = canadianPayment(loan, rate, amortization);
    return { downPct, base, premium, loan, monthly, total: monthly * amortization * 12, termCost: monthly * term * 12 };
  }, [home, down, amortization, term, rate]);
  const rows = [5, 10, 15, 20].map((pct) => { const base = 400000 * (1 - pct / 100); const premium = base * cmhcRate(pct); return [pct, cmhcRate(pct), premium, premium > 0 ? "Yes" : "No", canadianPayment(base + premium, 5, 25) - canadianPayment(base, 5, 25)] as const; });

  return (
    <>
      <SEOHead title="Free Canadian Mortgage Calculator Online - Calculate Canada Mortgage Payments Instantly | CalcHive" description="Free online Canadian mortgage calculator. Calculate mortgage payments following Canadian rules with CMHC insurance, semi-annual compounding and any amortization period instantly. 100% free, no signup required." canonical="/canadian-mortgage-calculator" keywords="free Canadian mortgage calculator, Canada mortgage calculator free online, CMHC calculator free, Canadian home loan calculator free, mortgage calculator Canada free" category="Financial Calculators" breadcrumbName="Free Canadian Mortgage Calculator Online" schemaType="WebApplication" schemaApplicationCategory="CalculatorApplication" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10"><div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-sky-600 dark:text-sky-400 bg-sky-50 dark:bg-sky-950/50 px-3 py-1 rounded-full mb-4 inline-block">Financial</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Canadian Mortgage Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Estimate Canadian mortgage payments with semi-annual compounding and CMHC insurance.</p></div><AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8"><div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8"><div><label className="text-sm font-semibold text-foreground block mb-2">Home price</label><input type="number" value={home} onChange={(e) => setHome(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold text-foreground block mb-2">Down payment</label><input type="number" value={down} onChange={(e) => setDown(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold text-foreground block mb-2">Amortization period years</label><input type="number" value={amortization} onChange={(e) => setAmortization(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold text-foreground block mb-2">Mortgage term years</label><input type="number" value={term} onChange={(e) => setTerm(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold text-foreground block mb-2">Interest rate (%)</label><input type="number" value={rate} onChange={(e) => setRate(Number(e.target.value))} className={inputClass} /></div></div><div className="bg-gradient-to-br from-sky-500 to-sky-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Monthly Payment</p><p className="text-5xl sm:text-6xl font-black text-white">{cad(result.monthly, 2)}</p></div><div className="grid grid-cols-1 sm:grid-cols-3 gap-3 mt-4"><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">CMHC premium</p><p className="text-lg font-extrabold text-foreground">{cad(result.premium)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Total mortgage</p><p className="text-lg font-extrabold text-foreground">{cad(result.loan)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Total cost</p><p className="text-lg font-extrabold text-foreground">{cad(result.total)}</p></div></div></section><ShareButton />
        <section className="mb-8 space-y-6"><h2 className="text-2xl font-bold text-foreground">How to Calculate Canadian Mortgage Payments for Free</h2><p className="text-muted-foreground leading-relaxed">This calculator converts Canada's semi-annual mortgage rate convention into an effective monthly rate, then includes CMHC insurance when the down payment is below 20%.</p><h2 className="text-2xl font-bold text-foreground">How CMHC Mortgage Insurance Works in Canada</h2><div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">Canadian CMHC Mortgage Insurance by Down Payment</caption><thead className="bg-muted/60"><tr>{["Down Payment %", "CMHC Premium Rate", "CMHC Amount on $400K", "Added to Mortgage", "Monthly Impact"].map((h) => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{rows.map((r) => <tr key={r[0]}><td className="py-2.5 px-3 font-semibold">{r[0]}%</td><td className="py-2.5 px-3">{(r[1] * 100).toFixed(2)}%</td><td className="py-2.5 px-3">{cad(r[2])}</td><td className="py-2.5 px-3">{r[3]}</td><td className="py-2.5 px-3">{cad(r[4], 2)}</td></tr>)}</tbody></table></div><h2 className="text-2xl font-bold text-foreground">Free Canada Mortgage Calculator for Canadian Home Buyers</h2></section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section><AdPlaceholder size="rectangle" className="mx-auto mb-8" /><RelatedTools exclude="/canadian-mortgage-calculator" headingLevel="h3" /></main>
    </>
  );
}


